     1→/**
     2→ * CortexBuild Ultimate — WebSocket Notifications Hook
     3→ * Real-time notifications, dashboard updates, and alerts
     4→ */
     5→import { useEffect, useRef, useCallback, useState } from 'react';
     6→
     7→const WS_URL = (() => {
     8→  const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
     9→  return `${proto}//${window.location.host}/ws`;
    10→})();
    11→
    12→type Notification = {
    13→  id: string;
    14→  type: 'notification' | 'alert' | 'dashboard_update' | 'collaboration' | 'system';
    15→  title: string;
    16→  description: string;
    17→  severity: 'info' | 'success' | 'warning' | 'error' | 'critical';
    18→  timestamp: string;
    19→  read: boolean;
    20→  data?: Record<string, unknown>;
    21→};
    22→
    23→interface UseNotificationsReturn {
    24→  notifications: Notification[];
    25→  unreadCount: number;
    26→  isConnected: boolean;
    27→  markAsRead: (id: string) => void;
    28→  markAllAsRead: () => void;
    29→  dismissNotification: (id: string) => void;
    30→  clearAll: () => void;
    31→}
    32→
    33→export function useNotifications(authToken: string | null): UseNotificationsReturn {
    34→  const ws = useRef<WebSocket | null>(null);
    35→  const [notifications, setNotifications] = useState<Notification[]>([]);
    36→  const [isConnected, setIsConnected] = useState(false);
    37→  const reconnectTimeout = useRef<NodeJS.Timeout | null>(null);
    38→
    39→  // Connect to WebSocket
    40→  const connect = useCallback(() => {
    41→    if (!authToken) return;
    42→
    43→    try {
    44→      ws.current = new WebSocket(`${WS_URL}?token=${authToken}`);
    45→
    46→      ws.current.onopen = () => {
    47→        console.log('[WS] Connected');
    48→        setIsConnected(true);
    49→      };
    50→
    51→      ws.current.onmessage = (event) => {
    52→        try {
    53→          const message = JSON.parse(event.data);
    54→          if (message.type && message.payload) {
    55→            const notification: Notification = {
    56→              id: `${message.type}-${Date.now()}`,
    57→              type: message.type,
    58→              title: message.payload.title || message.event,
    59→              description: message.payload.description || message.payload.message || '',
    60→              severity: message.payload.severity || message.payload.priority || 'info',
    61→              timestamp: message.payload.timestamp || new Date().toISOString(),
    62→              read: false,
    63→              data: message.payload,
    64→            };
    65→            setNotifications(prev => [notification, ...prev]);
    66→          }
    67→        } catch (err) {
    68→          console.error('[WS] Message parse error:', err);
    69→        }
    70→      };
    71→
    72→      ws.current.onclose = () => {
    73→        console.log('[WS] Disconnected');
    74→        setIsConnected(false);
    75→        // Attempt reconnection
    76→        reconnectTimeout.current = setTimeout(connect, 3000);
    77→      };
    78→
    79→      ws.current.onerror = (err) => {
    80→        console.error('[WS] Error:', err);
    81→      };
    82→    } catch (err) {
    83→      console.error('[WS] Connection error:', err);
    84→    }
    85→  }, [authToken]);
    86→
    87→  // Disconnect on unmount
    88→  useEffect(() => {
    89→    connect();
    90→    return () => {
    91→      if (ws.current) ws.current.close();
    92→      if (reconnectTimeout.current) clearTimeout(reconnectTimeout.current);
    93→    };
    94→  }, [connect]);
    95→
    96→  const markAsRead = useCallback((id: string) => {
    97→    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
    98→  }, []);
    99→
   100→  const markAllAsRead = useCallback(() => {
   101→    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
   102→  }, []);
   103→
   104→  const dismissNotification = useCallback((id: string) => {
   105→    setNotifications(prev => prev.filter(n => n.id !== id));
   106→  }, []);
   107→
   108→  const clearAll = useCallback(() => {
   109→    setNotifications([]);
   110→  }, []);
   111→
   112→  const unreadCount = notifications.filter(n => !n.read).length;
   113→
   114→  return {
   115→    notifications,
   116→    unreadCount,
   117→    isConnected,
   118→    markAsRead,
   119→    markAllAsRead,
   120→    dismissNotification,
   121→    clearAll,
   122→  };
   123→}
