     1→/**
     2→ * CortexBuild Ultimate — API Service
     3→ * All CRUD operations route to the local Express.js backend.
     4→ */
     5→import { getToken, API_BASE } from '../lib/supabase';
     6→
     7→type Row = Record<string, unknown>;
     8→
     9→// ─── snake_case → camelCase normalizer ───────────────────────────────────────
    10→
    11→function camelize(s: string): string {
    12→  return s.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
    13→}
    14→
    15→function toCamel<T>(obj: unknown): T {
    16→  if (Array.isArray(obj)) return obj.map(toCamel) as unknown as T;
    17→  if (obj !== null && typeof obj === 'object') {
    18→    return Object.fromEntries(
    19→      Object.entries(obj as Record<string, unknown>).map(([k, v]) => [camelize(k), toCamel(v)])
    20→    ) as unknown as T;
    21→  }
    22→  return obj as T;
    23→}
    24→
    25→// ─── Core fetch helper ────────────────────────────────────────────────────────
    26→
    27→async function apiFetch<T>(path: string, options?: RequestInit): Promise<T> {
    28→  const token = getToken();
    29→  const res = await fetch(`${API_BASE}${path}`, {
    30→    ...options,
    31→    headers: {
    32→      'Content-Type': 'application/json',
    33→      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    34→      ...options?.headers,
    35→    },
    36→  });
    37→  if (!res.ok) {
    38→    const err = await res.json().catch(() => ({ message: res.statusText }));
    39→    throw new Error(err.message || 'Request failed');
    40→  }
    41→  const data = await res.json();
    42→  return toCamel<T>(data);
    43→}
    44→
    45→async function fetchAll<T>(endpoint: string): Promise<T[]> {
    46→  return apiFetch<T[]>(`/${endpoint}`);
    47→}
    48→
    49→async function insertRow<T>(endpoint: string, row: Row): Promise<T> {
    50→  return apiFetch<T>(`/${endpoint}`, { method: 'POST', body: JSON.stringify(row) });
    51→}
    52→
    53→async function updateRow<T>(endpoint: string, id: string, data: Row): Promise<T> {
    54→  return apiFetch<T>(`/${endpoint}/${id}`, { method: 'PUT', body: JSON.stringify(data) });
    55→}
    56→
    57→async function deleteRow(endpoint: string, id: string): Promise<void> {
    58→  await apiFetch(`/${endpoint}/${id}`, { method: 'DELETE' });
    59→}
    60→
    61→// ─── Entity APIs ──────────────────────────────────────────────────────────────
    62→
    63→export const projectsApi = {
    64→  getAll: () => fetchAll('projects'),
    65→  getById: (id: string) => apiFetch(`/projects/${id}`),
    66→  create: (data: Row) => insertRow('projects', data),
    67→  update: (id: string, data: Row) => updateRow('projects', id, data),
    68→  delete: (id: string) => deleteRow('projects', id),
    69→};
    70→
    71→export const invoicesApi = {
    72→  getAll: () => fetchAll('invoices'),
    73→  getById: (id: string) => apiFetch(`/invoices/${id}`),
    74→  create: (data: Row) => insertRow('invoices', data),
    75→  update: (id: string, data: Row) => updateRow('invoices', id, data),
    76→  delete: (id: string) => deleteRow('invoices', id),
    77→};
    78→
    79→export const teamApi = {
    80→  getAll: () => fetchAll('team'),
    81→  getById: (id: string) => apiFetch(`/team/${id}`),
    82→  create: (data: Row) => insertRow('team', data),
    83→  update: (id: string, data: Row) => updateRow('team', id, data),
    84→  delete: (id: string) => deleteRow('team', id),
    85→};
    86→
    87→export const safetyApi = {
    88→  getAll: () => fetchAll('safety'),
