                    <td className="px-4 py-3"><button onClick={()=>toast.success('Invoice downloaded')} className="text-xs text-blue-400 hover:text-blue-300">Download</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
