            <div className="grid grid-cols-3 gap-4">
              {[
                {k:'email_digest',  label:'Email Digest',    desc:'Daily summary email at 7am'},
                {k:'sms_alerts',    label:'SMS Alerts',      desc:'Critical safety & overdue only'},
