                  <div>
                    <p className="text-white text-sm font-medium">{label}</p>
                    <p className="text-gray-400 text-xs mt-0.5">{desc}</p>
                  </div>
                  <Toggle on={notifs[k as keyof typeof notifs]} onToggle={()=>toggleNotif(k as keyof typeof notifs)}/>
