     1→// Module: Dashboard — CortexBuild Ultimate
     2→// "Site Command Center" Redesign — Industrial Intelligence Aesthetic
     3→import { useState, useMemo } from 'react';
     4→import {
     5→  TrendingUp, TrendingDown, FolderOpen, HardHat, FileText, ShieldCheck,
     6→  MessageSquare, AlertCircle, Activity, CheckCircle2, ArrowRight,
     7→  Cloud, CloudRain, Wind, Thermometer, MapPin, Eye, Bell, Zap,
     8→  Radar as RadarIcon, Layers, AlertTriangle, Clock, Users, Package, Truck,
     9→  ChevronRight, X, Play, Pause, RefreshCw, BarChart3, PieChart,
    10→  ClipboardList, ShoppingCart,
    11→} from 'lucide-react';
    12→import {
    13→  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    14→  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Legend,
    15→  BarChart, Bar, LabelList,
    16→} from 'recharts';
    17→import { useProjects, useInvoices, useTeam, useSafety, useRFIs, useDailyReports } from '../../hooks/useData';
    18→import type { Module } from '../../types';
    19→
    20→type AnyRow = Record<string, unknown>;
    21→
    22→interface DashboardProps {
    23→  setModule: (m: Module) => void;
    24→}
    25→
    26→const MONTH_ABBR = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    27→
    28→// Weather mock data — would integrate with OpenWeatherMap API in production
    29→const SITE_WEATHER = {
    30→  temp: 14,
    31→  condition: 'Partly Cloudy',
    32→  wind: 12,
    33→  humidity: 68,
    34→  forecast: 'Clear conditions for next 48h',
    35→};
    36→
    37→// Build monthly chart data from invoices
    38→function buildChartData(invoices: AnyRow[]) {
    39→  const now = new Date();
    40→  const months: { month: string; year: number; revenue: number; profit: number }[] = [];
    41→  for (let i = 5; i >= 0; i--) {
    42→    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    43→    months.push({ month: MONTH_ABBR[d.getMonth()], year: d.getFullYear(), revenue: 0, profit: 0 });
    44→  }
    45→  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    46→    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    47→    if (!dateStr) return;
    48→    const d = new Date(dateStr);
    49→    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && m.year === d.getFullYear());
    50→    if (mIdx !== -1) {
    51→      months[mIdx].revenue += Number(inv.amount ?? 0);
    52→      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    53→    }
    54→  });
    55→  return months.map(({ month, year, revenue, profit }) => ({ month, revenue, profit }));
    56→}
    57→
    58→// Project health dimensions for radar chart
    59→function buildHealthData(projects: AnyRow[], safety: AnyRow[], invoices: AnyRow[]) {
    60→  const active = projects.filter(p => p.status === 'active');
    61→  const avgProgress = active.length ? active.reduce((s, p) => s + Number(p.progress ?? 0), 0) / active.length : 0;
    62→  const budgetHealth = active.length ? active.reduce((s, p) => {
    63→    const burn = Number(p.spent ?? 0) / (Number(p.budget ?? 1) || 1);
    64→    return s + (1 - Math.abs(burn - Number(p.progress ?? 0) / 100));
    65→  }, 0) / active.length * 100 : 50;
    66→  const safetyScore = Math.max(0, 100 - safety.filter(s => ['open', 'investigating'].includes(String(s.status))).length * 15);
    67→  const rfiTurnaround = 70 - projects.length; // Simplified - would use actual RFI data
    68→  const cashHealth = invoices.length ? invoices.filter(i => i.status === 'paid').length / invoices.length * 100 : 50;
    69→  const compliance = 85; // Would be computed from RAMS expiry, training certs, etc.
    70→
    71→  return [
    72→    { dimension: 'Progress', score: Math.round(avgProgress), fullMark: 100 },
    73→    { dimension: 'Budget', score: Math.round(budgetHealth), fullMark: 100 },
    74→    { dimension: 'Safety', score: safetyScore, fullMark: 100 },
    75→    { dimension: 'RFIs', score: Math.max(0, rfiTurnaround), fullMark: 100 },
    76→    { dimension: 'Cash Flow', score: Math.round(cashHealth), fullMark: 100 },
    77→    { dimension: 'Compliance', score: compliance, fullMark: 100 },
    78→  ];
    79→}
    80→
    81→function fmtM(n: number) {
    82→  if (n >= 1_000_000) return `£${(n / 1_000_000).toFixed(2)}M`;
    83→  if (n >= 1_000)     return `£${(n / 1_000).toFixed(0)}K`;
    84→  return `£${n.toLocaleString()}`;
    85→}
    86→
    87→// Enhanced Stat Card with sparkline trend
    88→function StatCard({
    89→  label, value, sub, positive, icon: Icon, delay, onClick, trendData, secondaryValue,
    90→}: {
    91→  label: string; value: string; sub: string; positive: boolean;
    92→  icon: React.ComponentType<{ className?: string; size?: number; strokeWidth?: number }>;
    93→  delay: number; onClick?: () => void; trendData?: number[]; secondaryValue?: string;
    94→}) {
    95→  return (
    96→    <button
    97→      onClick={onClick}
    98→      className="card card-grid card-hover animate-fade-up"
    99→      style={{ animationDelay: `${delay}ms`, padding: '0', cursor: onClick ? 'pointer' : 'default', textAlign: 'left', width: '100%', border: 'none', overflow: 'hidden' }}
   100→    >
   101→      {/* Amber top accent line */}
   102→      <div style={{
   103→        position: 'absolute', top: 0, left: '0', right: '0', height: '3px',
   104→        background: positive
   105→          ? 'linear-gradient(90deg, var(--amber-500), var(--amber-400), var(--emerald-400))'
   106→          : 'linear-gradient(90deg, var(--slate-700), var(--red-400))',
   107→      }} />
   108→
   109→      <div style={{ padding: '18px', position: 'relative', zIndex: 1 }}>
   110→        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
   111→          <span className="text-label-xs" style={{ color: 'var(--slate-400)' }}>{label}</span>
   112→          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
   113→            {trendData && (
   114→              <div style={{ width: '40px', height: '24px', opacity: 0.6 }}>
   115→                <ResponsiveContainer width="100%" height="100%">
   116→                  <AreaChart data={trendData.map((v, i) => ({ i, v }))}>
   117→                    <Area type="monotone" dataKey="v" stroke={positive ? 'var(--emerald-400)' : 'var(--red-400)'} fill="none" strokeWidth={1.5} />
   118→                  </AreaChart>
   119→                </ResponsiveContainer>
   120→              </div>

