// ─── Stat block ──────────────────────────────────────────────────────────
function StatBlock({ value, suffix, label, delay }: { value: number; suffix: string; label: string; delay: number }) {
  const count = useCounter(value, 2000, delay);
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{
        fontFamily: "'Syne', sans-serif",
        fontWeight: 800,
        fontSize: 'clamp(1.5rem, 3vw, 2.2rem)',
        color: '#f59e0b',
        lineHeight: 1,
        letterSpacing: '-0.03em',
      }}>
        {count.toLocaleString()}{suffix}
      </div>
      <div style={{
        fontFamily: "'JetBrains Mono', monospace",
        fontSize: '9px',
        color: 'rgba(138,155,181,0.8)',
        textTransform: 'uppercase',
        letterSpacing: '0.12em',
        marginTop: '5px',
      }}>
        {label}
      </div>
    </div>
  );
}

// ─── Feature pill ─────────────────────────────────────────────────────────
function FeaturePill({ icon: Icon, text, delay }: { icon: React.ComponentType<{size?: number; style?: React.CSSProperties}>; text: string; delay: string }) {
  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      padding: '7px 14px',
      background: 'rgba(245,158,11,0.07)',
      border: '1px solid rgba(245,158,11,0.15)',
      borderRadius: '100px',
      animation: `slideUp 0.6s ease ${delay} both`,
    }}>
      <Icon size={13} style={{ color: '#f59e0b' }} />
      <span style={{
        fontFamily: "'DM Sans', sans-serif",
        fontSize: '12px',
        fontWeight: 500,
        color: 'rgba(226,232,240,0.85)',
        letterSpacing: '0.01em',
      }}>{text}</span>
    </div>
  );
}

